def merge_within(pairs):
    merged = sorted(pairs)
    result = []
    current_end = None

    for pair in merged:
        if current_end is not None and current_end >= pair[0]:
            current_end = max(current_end, pair[1])
        else:
            result.append([pair[0], pair[1]])
            current_end = pair[1]

    return result or [()]  # special case for empty list: returns an empty tuple to be consistent with the rest of the results
